import javax.crypto.spec.SecretKeySpec;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.Arrays;

/**
 * AES encryption utility class for encrypting data with a provided key.
 * This class provides a static method to encrypt byte array data using AES algorithm
 * and returns the result as a hexadecimal string.
 */
public class AESService {

    private static final String ALGORITHM = "AES";
    private static final String TRANSFORMATION = "AES/ECB/PKCS5Padding";

    /**
     * Encrypts the given data using AES encryption with the provided key.
     * 
     * @param key  The encryption key as a string. Will be hashed to create a valid AES key.
     * @param data The plaintext data to encrypt as a byte array.
     * @return The encrypted ciphertext as a hexadecimal string, or null if encryption fails.
     */
    public static String encrypt(String key, byte[] data) {
        try {
            // Handle null inputs
            if (key == null || data == null) {
                return null;
            }

            // Generate a 128-bit (16 bytes) AES key from the provided string key
            MessageDigest sha = MessageDigest.getInstance("SHA-256");
            byte[] keyBytes = sha.digest(key.getBytes("UTF-8"));
            keyBytes = Arrays.copyOf(keyBytes, 16); // Use first 128 bits

            // Create secret key specification
            SecretKeySpec secretKey = new SecretKeySpec(keyBytes, ALGORITHM);

            // Initialize cipher for encryption
            Cipher cipher = Cipher.getInstance(TRANSFORMATION);
            cipher.init(Cipher.ENCRYPT_MODE, secretKey);

            // Perform encryption
            byte[] encryptedBytes = cipher.doFinal(data);

            // Convert to hexadecimal string
            StringBuilder hexString = new StringBuilder();
            for (byte b : encryptedBytes) {
                String hex = Integer.toHexString(0xff & b);
                if (hex.length() == 1) {
                    hexString.append('0');
                }
                hexString.append(hex);
            }

            return hexString.toString();

        } catch (Exception e) {
            // Log the exception in a real application
            return null;
        }
    }
}

